"use client";

import type {ButtonProps} from "fumadocs-ui/components/ui/button";
import type {ComponentProps} from "react";

import {buttonVariants} from "fumadocs-ui/components/ui/button";
import {useI18n} from "fumadocs-ui/contexts/i18n";
import {useSearchContext} from "fumadocs-ui/contexts/search";

import {Search} from "@/components/fumadocs/ui/icons";
import {cn} from "@/utils/cn";

interface SearchToggleProps extends Omit<ComponentProps<"button">, "color">, ButtonProps {
  hideIfDisabled?: boolean;
}

export function SearchToggle({
  color = "ghost",
  hideIfDisabled,
  size = "icon-sm",
  ...props
}: SearchToggleProps) {
  const {enabled, setOpenSearch} = useSearchContext();

  if (hideIfDisabled && !enabled) return null;

  return (
    <button
      aria-label="Open Search"
      data-search=""
      type="button"
      className={cn(
        buttonVariants({
          color,
          size,
        }),
        props.className,
      )}
      onClick={() => {
        setOpenSearch(true);
      }}
    >
      <Search />
    </button>
  );
}

export function LargeSearchToggle({
  hideIfDisabled,
  ...props
}: ComponentProps<"button"> & {
  hideIfDisabled?: boolean;
}) {
  const {enabled, hotKey, setOpenSearch} = useSearchContext();
  const {text} = useI18n();

  if (hideIfDisabled && !enabled) return null;

  return (
    <button
      data-search-full=""
      type="button"
      {...props}
      className={cn(
        "bg-fd-secondary/50 text-fd-muted-foreground hover:bg-fd-accent hover:text-fd-accent-foreground inline-flex items-center gap-2 rounded-lg border p-1.5 ps-2 text-sm transition-colors",
        props.className,
      )}
      onClick={() => {
        setOpenSearch(true);
      }}
    >
      <Search className="size-4" />
      {text.search}
      <div className="ms-auto inline-flex gap-0.5">
        {hotKey.map((k, i) => (
          <kbd key={i} className="bg-fd-background rounded-md border px-1.5">
            {k.display}
          </kbd>
        ))}
      </div>
    </button>
  );
}

"use client";

import type {ComponentProps} from "react";

import {useTheme} from "next-themes";
import {tv} from "tailwind-variants";

import {Airplay, Moon, Sun} from "@/components/fumadocs/ui/icons";
import {useIsMounted} from "@/hooks/use-is-mounted";
import {cn} from "@/utils/cn";

const itemVariants = tv({
  base: "text-fd-muted-foreground size-6.5 rounded-full p-1.5",
  variants: {
    active: {
      false: "text-fd-muted-foreground",
      true: "bg-fd-accent text-fd-accent-foreground",
    },
  },
});

const full = [["light", Sun] as const, ["dark", Moon] as const, ["system", Airplay] as const];

export function ThemeToggle({
  className,
  mode = "light-dark",
  ...props
}: ComponentProps<"div"> & {
  mode?: "light-dark" | "light-dark-system";
}) {
  const {resolvedTheme, setTheme, theme} = useTheme();
  const mounted = useIsMounted();

  const container = cn(
    "inline-flex cursor-(--cursor-interactive) items-center rounded-full border p-1",
    className,
  );

  if (mode === "light-dark") {
    const value = mounted ? resolvedTheme : null;

    return (
      <button
        aria-label="Toggle Theme"
        className={container}
        data-theme-toggle=""
        onClick={() => setTheme(value === "light" ? "dark" : "light")}
      >
        {full.map(([key, Icon]) => {
          if (key === "system") return;

          return (
            <Icon
              key={key}
              className={cn(itemVariants({active: value === key}))}
              fill="currentColor"
            />
          );
        })}
      </button>
    );
  }

  const value = mounted ? theme : null;

  return (
    <div className={container} data-theme-toggle="" {...props}>
      {full.map(([key, Icon]) => (
        <button
          key={key}
          aria-label={key}
          className={cn(itemVariants({active: value === key}))}
          onClick={() => setTheme(key)}
        >
          <Icon className="size-full" fill="currentColor" />
        </button>
      ))}
    </div>
  );
}

import type {ColorVariableValue} from "../../hooks/use-color-variables";

import React from "react";

import {groupVariablesByCategory} from "../../hooks/use-color-variables";

interface ColorVariablesListProps {
  variables: ColorVariableValue[];
}

interface ColorSwatchProps {
  value: string;
  name: string;
}

function ColorSwatch({name, value}: ColorSwatchProps) {
  return (
    <div
      className="size-6 shrink-0 rounded border border-border/50"
      style={{backgroundColor: value}}
      title={`${name}: ${value}`}
    />
  );
}

interface ColorVariableRowProps {
  variable: ColorVariableValue;
}

function ColorVariableRow({variable}: ColorVariableRowProps) {
  const displayValue = variable.computedValue || variable.rawValue || "unset";

  return (
    <div className="flex items-start gap-2 py-1">
      <div className="flex flex-col gap-0.5">
        <div className="flex items-center gap-2">
          <span className="font-mono text-xs font-semibold text-foreground">{variable.name}</span>
          <ColorSwatch name={variable.name} value={displayValue} />
        </div>
        <span className="font-mono text-xs text-accent">{displayValue}</span>
      </div>
    </div>
  );
}

export function ColorVariablesList({variables}: ColorVariablesListProps) {
  const groupedVariables = groupVariablesByCategory(variables);

  const categoryOrder = [
    "primitive",
    "base",
    "surface",
    "overlay",
    "semantic",
    "accent",
    "status",
    "field",
    "border",
  ];

  const categoryLabels: Record<string, string> = {
    primitive: "Primitives",
    base: "Base",
    surface: "Surface",
    overlay: "Overlay",
    semantic: "Semantic",
    accent: "Accent",
    status: "Status",
    field: "Fields",
    border: "Borders",
  };

  return (
    <div className="flex h-full flex-col gap-4 overflow-y-auto pr-2 text-sm">
      {categoryOrder.map((category) => {
        const categoryVars = groupedVariables[category];

        if (!categoryVars || categoryVars.length === 0) return null;

        return (
          <div key={category} className="flex flex-col gap-1">
            <h3 className="mb-1 text-xs font-semibold tracking-wider text-muted uppercase">
              {categoryLabels[category] || category}
            </h3>
            {categoryVars.map((variable) => (
              <ColorVariableRow key={variable.name} variable={variable} />
            ))}
          </div>
        );
      })}
    </div>
  );
}

"use client";

import React from "react";

import {cn} from "@/utils/cn";

interface HorizontalScrollingBannerProps {
  children: React.ReactNode;
  className?: string;
  duration?: number; // in seconds
  gap?: string;
  isReverse?: boolean;
  shouldPauseOnHover?: boolean;
  showShadow?: boolean;
  shadowSize?: string;
}

const HorizontalScrollingBanner = React.forwardRef<HTMLDivElement, HorizontalScrollingBannerProps>(
  (
    {
      children,
      className,
      duration = 40,
      gap = "1rem",
      isReverse = false,
      shadowSize = "60px",
      shouldPauseOnHover = true,
      showShadow = true,
    },
    ref,
  ) => {
    const maskImage = showShadow
      ? `linear-gradient(to right, transparent, #000 ${shadowSize}, #000 calc(100% - ${shadowSize}), transparent)`
      : undefined;

    return (
      <div
        ref={ref}
        className={cn("flex w-full overflow-x-hidden", className)}
        style={
          {
            "--duration": `${duration}s`,
            "--gap": gap,
            WebkitMaskImage: maskImage,
            maskImage,
          } as React.CSSProperties
        }
      >
        <div
          className="flex w-max items-stretch"
          style={{
            animation: `scrolling-banner var(--duration) linear infinite`,
            animationDirection: isReverse ? "reverse" : "normal",
            gap: `var(--gap)`,
          }}
          onMouseEnter={(e) => {
            if (shouldPauseOnHover) {
              e.currentTarget.style.animationPlayState = "paused";
            }
          }}
          onMouseLeave={(e) => {
            if (shouldPauseOnHover) {
              e.currentTarget.style.animationPlayState = "running";
            }
          }}
        >
          {/* Clone children and duplicate for seamless loop */}
          {React.Children.map(children, (child, index) => (
            <div key={`original-${index}`} className="shrink-0">
              {React.cloneElement(child as React.ReactElement)}
            </div>
          ))}
          {React.Children.map(children, (child, index) => (
            <div key={`duplicate-${index}`} className="shrink-0">
              {React.cloneElement(child as React.ReactElement)}
            </div>
          ))}
        </div>
      </div>
    );
  },
);

HorizontalScrollingBanner.displayName = "HorizontalScrollingBanner";

export default HorizontalScrollingBanner;

"use client";

import {CodeBlock, Pre} from "fumadocs-ui/components/codeblock";
import * as TabsComponents from "fumadocs-ui/components/tabs";

import {BunIcon, CLIBoldIcon, NpmSmallIcon, PnpmIcon, YarnIcon} from "@/icons/dev";

const {Tabs, TabsContent, TabsList, TabsTrigger} = TabsComponents;

type PackageManagerName = "cli" | "npm" | "yarn" | "pnpm" | "bun";

type PackageManager = {
  icon: React.ReactNode;
  name: PackageManagerName;
  label?: string;
};

const packageManagers: PackageManager[] = [
  {
    icon: <CLIBoldIcon className="text-lg text-foreground" />,
    label: "CLI",
    name: "cli",
  },
  {
    icon: <PnpmIcon className="text-foreground" />,
    name: "pnpm",
  },
  {
    icon: <NpmSmallIcon className="text-foreground" />,
    name: "npm",
  },
  {
    icon: <YarnIcon className="text-foreground" />,
    name: "yarn",
  },
  {
    icon: <BunIcon className="text-foreground" />,
    name: "bun",
  },
];

export interface PackageManagersProps {
  commands: Partial<Record<PackageManagerName, string>>;
}

export const PackageManagers = ({commands}: PackageManagersProps) => {
  // Get the first available command as default
  const availableManagers = packageManagers.filter((pm) => commands[pm.name]);
  const defaultValue = availableManagers[0]?.name || "npm";

  return (
    <>
      <Tabs
        className="mt-4 w-full min-w-[300px] border-none bg-transparent"
        defaultValue={defaultValue}
      >
        <TabsList className="mb-1 h-10 overflow-x-auto">
          {packageManagers.map(({label, name}) => {
            if (!commands[name]) return null;

            return (
              <TabsTrigger key={name} className="flex items-center gap-2" value={name}>
                <span>{label || name}</span>
              </TabsTrigger>
            );
          })}
        </TabsList>
        {packageManagers.map(({name}) => {
          if (!commands[name]) return null;

          return (
            <TabsContent key={name} className="bg-transparent" value={name}>
              <CodeBlock lang="bash">
                <Pre className="px-3">{commands[name]}</Pre>
              </CodeBlock>
            </TabsContent>
          );
        })}
      </Tabs>
    </>
  );
};

